scwin.f_Save = async function () {
  if (ed_stdYyyy.getValue().trim() != scwin.hid_stdYyyy) {
    await $c.gus.cfAlertMsg($p, "조회 조건인 기준년도가 변경되어서 저장 하실 수 없습니다. 재 조회 및 엑셀파일 Import를 다시 실행하시기 바랍니다.");
    return;
  }
  if (ds_master.getModifiedIndex().length <= 0) {
    await $c.win.alert($p, "변경된 사항이 없습니다.");
    //await $c.win.alert($c.data.getMessage(MSG_CM_ERR_001, [""]));
    return;
  }
  // 변경된 사항이 있는지 확인.
  var tmm = "";
  var rcnt = ds_master.getRowCount();
  const cols = ["jan", "feb", "mar", "apr", "may", "jun", "jul", "aug", "sep", "oct", "nov", "dec"];
  for (var i = 0; i <= rcnt; i++) {
    if (ds_master.getRowStatus(i) == "C" || ds_master.getRowStatus(i) == "U") {
      ds_master.setCellData(i, "chk", "F");
      ds_master.setCellData(i, "stdYyyy", scwin.hid_stdYyyy);
      tmm = String(i + 1);
      ds_master.setCellData(i, "stdYm", scwin.hid_stdYyyy + $c.gus.cfGetFormatStr($p, tmm, "0#"));
      if ($c.gus.cfIsNull($p, ds_master.getCellData(i, "acctDeptCd"))) {
        await $c.gus.cfAlertMsg($p, i + 1 + "번째 행의  귀속코드 코드값이 없습니다. 확인하시기 바랍니다.");
        gr_ClntControl.setFocusedCell(i, "acctDeptCd", true);
        return true;
      }
      if ($c.gus.cfIsNull($p, ds_master.getCellData(i, "transCargoClsCd"))) {
        await $c.gus.cfAlertMsg($p, i + 1 + "번째 행의  구분코드 코드값이 없습니다. 확인하시기 바랍니다.");
        gr_ClntControl.setFocusedCell(i, "transCargoClsCd", true);
        return true;
      }
      // 인원수에 대한 자릿수를 체크한다.
      t_StaffCnt = 0;
      for (var j = 0; j < cols.length; j++) {
        if ($c.gus.cfIsNull($p, ds_master.getCellData(i, cols[j])) || ds_master.getCellData(i, cols[j]) > 99999) {
          await $c.gus.cfAlertMsg($p, String(j + 1) + "월의 입력가능 범위를 초과 하였습니다. 확인하시기 바랍니다.");
          gr_ClntControl.setFocusedCell(i, cols[j], true);
          return true;
        }
        t_StaffCnt = t_StaffCnt + $c.num.parseInt($p, ds_master.getCellData(i, cols[j]));
      }
      ds_master.setCellData(i, "staffCnt", t_StaffCnt);
    }
  }

  // 필수입력사항 확인
  //    if (!$c.gus.cfValidate([gr_ClntControl])) {
  //        return;
  //    }    

  if ((await $c.win.confirm($p, MSG_CM_CRM_001)) == false) {
    return;
  }
  var rs = $c.sbm.execute($p, sbm_Save);

  //if (rs.responseJSON.resultDataSet[0].code == "1"){
  //    await $c.win.alert(MSG_CM_INF_001);	// 성공적으로 저장하였습니다.
  //    ds_master.reform();
  //    scwin.f_Retrieve();
  //}    
};

