scwin.ds_master_ondataload = function () {
  var rowCnt = ds_master.getTotalRow();
  totalRows.setValue(rowCnt);
  if (rowCnt == 0) {
    if ($c.gus.cfCheckCreateFlag($p) == true) {
      $c.gus.cfTurnCreateFlag($p, false);
    } else {
      $c.gus.cfAlertMsg($p, MSG_CM_WRN_002);
    }
    $c.gus.cfEnableObjects($p, [btn_AddRow, btn_undoRow, btn_Save]);
    return;
  }
  if (rowCnt > 0) {
    // ds_master.multisort(scwin.sort_options);  
    $c.gus.cfEnableObjects($p, [btn_AddRow, btn_AllDeleteRow, btn_undoRow, btn_Save]);
    ds_master.setRowPosition(rowCnt);
  }
};

